import React, { useState } from 'react';

function BackToTopButton({scrollPercentage}) {
  const [visible, setVisible] = useState(false);

  const handleScroll = (percentage) => {
    setVisible(percentage > 25); // Cambia 25 por el porcentaje deseado para mostrar el botón
  };

  const scrollToTop = () => {
    window.scrollTo({
      top: 0,
      behavior: 'smooth'
    });
  };

  return (
    <div>
      <ScrollListener onScroll={handleScroll} />
      <button onClick={scrollToTop} className={`back-to-top ${visible ? 'visible' : ''}`}>
        ↑
      </button>
    </div>
  );
}

export default BackToTopButton;
